var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"슬슬 성무 SI3E의 윤곽이 읽히기 시작하는군요.","JPN":"そろそろ聖務SI3Eの輪郭が読めてきましたね。","ENG":"The outline of Sacred Mission SI3E is starting to become legible.","TWN":"聖務SI3E的輪廓似乎越來越清晰。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대낮에 시체들을 조종하고, 인신공양 같은 짓을 저지를 수 있는 집단은 제가 아는 한 하나밖에 없습니다.","JPN":"真っ昼間に死体を操ったり、生贄を捧げたりできる集団は、私の知る限り一つしかありません。","ENG":"There is only one organization that I am aware of that would control corpses in broad daylight and commit human sacrifice.","TWN":"可以在大白天控制屍體進行活祭的團體，據我所知只有一個。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"에크하르트 초월지식 학회. 지식의 호수란 존재를 숭배하는 오컬트 단체죠.","JPN":"エクハルト超越知識学会。知識の湖という存在を崇めるオカルト団体です。","ENG":"ESPR, an occult organization that worships a being called the \\"Lake of Knowledge\\".","TWN":"埃克哈特超越學會，崇拜知識湖水的神秘組織。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"처음 들어보는데? 유명한 데야?","JPN":"初めて聞くけど。有名なの？","ENG":"First time hearing about them. Are they famous?","TWN":"我第一次聽到欸？很有名嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"지금 같은 형태를 갖춘 것은 비교적 최근으로 추정되지만…….","JPN":"今のような形になったのは比較的最近だと思われますが……","ENG":"The current form of the organization is assumed to be recent...","TWN":"應該是近期才發展到現在的規模……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청의 비밀서고에는 오래 전부터 이름을 바꾸며 명맥을 이어 온 사악한 불신자들에 대한 기록이 남아 있습니다.","JPN":"聖皇庁の秘密書庫には昔から名を変えながら脈々と受け継がれてきた邪悪な不信者たちの記録が残っています。","ENG":"However, the Holy Curia's secret archives contain records of morally corrupt unbelievers who for many years have carried on its legacy while changing its name.","TWN":"根據聖皇廳秘密書庫裡的紀錄，這些邪惡的不信者存在已久，中間換過許多名字。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"거짓 기적으로 위정자들을 현혹시키면서, 그릇된 지식을 무분별하게 탐닉하는 광인들.","JPN":"偽りの奇跡で為政者を惑わし、誤った知識に見境もなく溺れる狂人たち。","ENG":"They are maniacs that indulge in erroneous knowledge and deceive rulers with false miracles.","TWN":"他們用假的神蹟蒙騙執政者，同時沉溺於錯誤的知識。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇기에 만행이 극에 달하면 의인들의 손에 무너져 왔습니다. 연구를 구실로 흑사병 따위를 퍼뜨리는 자들이니까요.\xA0\xA0","JPN":"そのため、蛮行の限りを尽くすと義人の手によって成敗されてきました。研究を口実にペストなどを広めた人たちですから。\xA0\xA0","ENG":"So, when their atrocities reached their peak, they were smote by the hands of justice. They were, after all, the ones who spread the Black Death under the pretext of research.\xA0\xA0","TWN":"這樣作惡多端後，最後在義人的手中瓦解。他們還假研究之名散佈黑死病。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그럼, 그냥 쪼다들 노는 데 아냐.","JPN":"じゃあ、それって単に出来損ないの集団じゃない。","ENG":"Then, aren't they just losers?","TWN":"看來不是一群傻瓜聚集的組織。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그 쪼다들이 클로디아를 <color=#ffd34c>그렇게</color> 만들었다고?","JPN":"そいつらがクラウディアを<color=#ffd34c>あんな風に</color>したってこと？","ENG":"Those losers made Claudia like <color=#ffd34c>THAT</color>?!","TWN":"是他們把克勞迪婭弄成<color=#ffd34c>那樣</color>的嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청은 그들을 공식적으로 인정할 수 없으니까요.","JPN":"聖皇庁は公式的に彼らを認めることができないのです。","ENG":"This is due to the Holy Curia's refusal to officially recognize them.","TWN":"聖皇廳無法公開承認他們。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"우리 입장에서 그들은 어디까지나 2,000년 동안 수없이 나타나고 사라졌던 이단 중에 하나일 뿐입니다.","JPN":"私たちからすれば、彼らはあくまでも2,000年の間数えきれないほど現れては消えた異端の一つに過ぎません。","ENG":"To us, they are just one of many heretics that have appeared and vanished over the last 2,000 years.","TWN":"對我們而言，他們就只是這2,000年來，許許多多冒出頭後又消失的異端之一。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그런 것치고 안경 언니는 꽤 상세하게 알고 있네?","JPN":"そういう割には、お姉さんは結構詳しいんだね。","ENG":"And yet, you seem to know quite a lot about them, eh?","TWN":"不過四眼姊姊，你知道的還真多呢？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제 지식은 아닙니다.","JPN":"私の知識ではありません。","ENG":"This knowledge is not my own.","TWN":"不是我的知識，"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"교단 내부에서도 지극히 불경하고 이단적이라고 평가받은 1,057페이지의 보고서 중 일부일 뿐이니까요.","JPN":"教団内部でも極めて不敬で異端的と評価された1,057ページにわたる報告書の一部にすぎませんので。","ENG":"It is part of a 1,057-page report that the Church considered extremely sacrilegious.","TWN":"這只是教團內部評為極度邪惡不敬的1,057頁報告中的一部分而已。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이쯤 되면 그 보고서를 누가 썼는지…… 짐작이 가시겠죠?","JPN":"ここまで来たらその報告書を書いた人物が誰か……おわかりですね。","ENG":"By now, you can probably guess... who wrote this report?","TWN":"話說到這邊，你應該可以猜到……那份報告是誰寫的吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……적이 물러나는군.","JPN":"……敵が退いていく。","ENG":"The enemy is retreating.","TWN":"……敵人撤退了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};